import React, { useEffect, useState } from "react";

function Dashboard() {
  const [enquiries, setEnquiries] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetch("http://localhost:5000/api/enquiry")
      .then((res) => res.json())
      .then((data) => {
        console.log("Fetched from backend:", data); // DEBUG
        setEnquiries(data);
        setLoading(false);
      })
      .catch((err) => {
        console.error("Fetch error:", err);
        setLoading(false);
      });
  }, []);

  if (loading) {
    return <p style={{ padding: "20px" }}>Loading enquiries...</p>;
  }

  return (
    <div className="dashboard">
      <h2>Client Enquiries</h2>

      {enquiries.length === 0 ? (
        <p>No enquiries found</p>
      ) : (
        <table>
          <thead>
            <tr>
              <th>Name</th>
              <th>Phone</th>
              <th>Location</th>
              <th>Service</th>
              <th>Message</th>
            </tr>
          </thead>

          <tbody>
            {enquiries.map((e) => (
              <tr key={e._id}>
                <td>{e.name}</td>
                <td>{e.phone}</td>
                <td>{e.location}</td>
                <td>{e.service}</td>
                <td>{e.message}</td>
              </tr>
            ))}
          </tbody>
        </table>
      )}
    </div>
  );
}

export default Dashboard;
